import React from 'react';

export default function TaskCard({ task, onMove }){
  return (
    <div className="task card">
      <h5>{task.title}</h5>
      <div className="meta">Priority: {task.priority}</div>
      <div className="actions">
        {task.status!=='todo' && <button onClick={()=>onMove('todo')}>To Todo</button>}
        {task.status!=='inprogress' && <button onClick={()=>onMove('inprogress')}>In Progress</button>}
        {task.status!=='review' && <button onClick={()=>onMove('review')}>Review</button>}
        {task.status!=='done' && <button onClick={()=>onMove('done')}>Done</button>}
      </div>
    </div>
  )
}
